turn3_code:
FORUM_POST_FORMAT = "<h2>{header}</h2><p>{message}</p>{options}"

def create_post_html(post_title, post_body):
    return f"<h2>{post_title}</h2><p>{post_body}</p>"

def format_discussion_points(points):
    list_items = ''.join([f'<li>{point}</li>' for point in points])
    return f'<ul>{list_items}</ul>'

def build_forum_entry(post_title, post_body, bullet_points):
    options = format_discussion_points(bullet_points)
    return FORUM_POST_FORMAT.format(header=post_title, message=post_body, options=options)

turn2_code:
def basic_forum_post(post_title, post_body, discussion_points):
    points_str = ''.join([f"<item>{point}</item>" for point in discussion_points])
    return f"<title>{post_title}</title><content>{post_body}</content><discussion>{points_str}</discussion>"

turn3_code:
import html

FORUM_POST_FORMAT = "<h2>{header}</h2><p>{message}</p>{options}"

def build_forum_entry(post_title, post_body, bullet_points):
    escaped_title = html.escape(post_title)
    escaped_body = html.escape(post_body)

    if bullet_points:
        list_items = ''.join([f"<li>{html.escape(point)}</li>" for point in bullet_points])
        options_html = f"<ul>{list_items}</ul>"
    else:
        options_html = ""

    return FORUM_POST_FORMAT.format(
        header=escaped_title,
        message=escaped_body,
        options=options_html
    )
